#define N 10010



struct Edge{

	int y;

	int z;

	int w;

	Edge(){}

	Edge(int y,int z,int w):y(y),z(z),w(w){}

	bool operator <(const Edge&_x)const{

		return this->z>_x.z || (this->z==_x.z && this->w>_x.w);

	}

};

#define Node Edge



std::vector<Edge> v[N];



void Dijkstra(int&);



int main(){

	while(true){

		int n,m;

		scanf("%d%d",&n,&m);

		if(!(n||m))

			break;

		for(int i=1;i<=n;i++)

			v[i].clear();

		while(m--){

			int x,y,z,w;

			scanf("%d%d%d%d",&x,&y,&z,&w);

			v[x].push_back(Edge(y,z,w));

			v[y].push_back(Edge(x,z,w));

		}

		int ans=0;

		Dijkstra(ans);

		printf("%d\n",ans);

	}

	return 0;

}



void Dijkstra(int &ans){

	std::priority_queue<Node> q;

	q.push(Node(1,0,0));

	bool vis[N]={};

	while(q.size()){

		int x=q.top().y,z=q.top().z,w=q.top().w;

		q.pop();

		if(vis[x])

			continue;

		vis[x]=true;

		ans+=w;

		for(auto p:v[x])

			q.push(Node(p.y,z+p.z,p.w));

	}

}

